async def __run_python(code:str, g=None, ok_dests=None):
    _rp_globals.set(g)
    def unpack(a,*args): return list(a)
    rg =g | dict(__builtins__=_builtins, _getattr_=getattr, _inplacevar_ = _inplacevar_, type = type,
        _getitem_=lambda o,k: o[k], _getiter_=iter, _apply_ = lambda f, *a, **kw: f(*a, **kw),
        _write_=_default_write_, __metaclass__=type, __name__='<pyrun>',
        _print_=_DirectPrint, _print=_DirectPrint(),
        _unpack_sequence_=unpack, _iter_unpack_sequence_=unpack)
    loc = {}
    async def run(src, is_exec=True):
        try:
            comp = compile_restricted(src, srcfn(src), 'exec' if is_exec else 'eval', policy=SafeTransformer)
            r = eval(comp, rg, loc)
            return (await r) if inspect.isawaitable(r) else r
        except SyntaxError as e:
            if isinstance(e.msg, tuple): raise SyntaxError('\n'.join(e.msg)) from None
            raise
    tree = ast.parse(code)
    warnings.filterwarnings('ignore', category=SyntaxWarning)
    res = None
    if tree.body and isinstance(tree.body[-1], ast.Expr):
        last = tree.body.pop()
        if tree.body: await run(ast.unparse(ast.Module(tree.body, [])))
        res = await run(ast.unparse(ast.Expression(last.value)), False)
    else: await run(code)
    g.update(filter_dict(loc, lambda k,v: should_export(k, v, g)))
    return res

