default_ok_dests = ()

# %% ../nbs/02_safer.ipynb #5447b52c
class RunPython:
    """Execute restricted Python with access to LLM tools, returning last expression.
    `import` works in the usual way. All builtins are available.
    Multiline code blocks can be used, including defining functions and variables, for use within the call.

    **NB**: Locals are exported back to the caller's namespace unless they'd shadow an existing callable or module.
    - Symbols ending with `_` are always exported, even if they shadow existing names.
    Examples: `len([1,2,3])` (builtin); `add_msg(content="hi")` (tool); `df.shape` (non-callable attr);
    `[x**2 for x in range(5)]` (last expression returned); `sorted(my_dict.items())` (builtin + non-callable attr)"""

    def __init__(self, g=None, sentinel=None, ok_dests=UNSET):
        if ok_dests is UNSET: ok_dests = default_ok_dests
        self.g = _find_frame_dict(sentinel) if g is None else g
        self.ok_dests = ok_dests or ()

    async def __call__(self, code:str):
        try: return await _run_python(code, g=self.g, ok_dests=self.ok_dests)
        except Exception as e:
            tb = e.__traceback__
            while tb.tb_next and not tb.tb_frame.f_code.co_filename.startswith('<pyrun'): tb = tb.tb_next
            raise e.with_traceback(tb) from None

# %% ../nbs/02_safer.ipynb #9105f690
def create_pyrun_magic(shell=None, pyrun=None):
    "Create magic"
    if not shell: shell = get_ipython()
    if not pyrun: pyrun = RunPython()
    def f(line, cell=None):
        if line=='-o': return pyrun
        if not cell: return
        return pyrun(cell)
    shell.register_magic_function(f, 'line_cell', 'py')

